document.addEventListener('DOMContentLoaded', function () {
    // Function to update the text of the "VER +" buttons to "READ MORE"
    function updateReadMoreText() {
        const readMoreButtons = document.querySelectorAll('.em-item-read-more.button span');
        readMoreButtons.forEach(function (button) {
            if (button.textContent.trim() === "VER +") {
                button.textContent = "READ MORE";
            }
        });
    }

    // Function to update placeholders and button text on initial load
    function updateInitialText() {
        // Change the placeholder value for the search input
        const searchInput = document.querySelector('input[name="em_search"]');
        if (searchInput) {
            searchInput.placeholder = "Search";
        }

        // Change the placeholder value for the date input
        const dateInput = document.querySelector('.em-date-input.em-search-scope');
        if (dateInput) {
            dateInput.placeholder = "Date";
        }

        // Change the text of the search button
        const searchButton = document.querySelector('.em-search-submit.button-primary');
        if (searchButton) {
            searchButton.textContent = "Search";
        }

        // Update the "VER +" buttons initially
        updateReadMoreText();
    }

    // Run the initial updates if the URL matches
    if (window.location.href === "https://ani.pt/en/detailed-search-for-calls/") {
        updateInitialText();

        // Add a global event listener for AJAX complete (specific to WordPress and Events Manager)
        jQuery(document).on('ajaxComplete', function () {
            updateReadMoreText();
        });
    }
});

