document.addEventListener('DOMContentLoaded', function () {
    // Function to update the text of the "VER +" buttons to "READ MORE"
    function updateReadMoreText() {
        const readMoreButtons = document.querySelectorAll('.em-item-read-more.button span');
        readMoreButtons.forEach(function (button) {
            if (button.textContent.trim() === "VER +") {
                button.textContent = "READ MORE";
            }
        });
    }

    // Function to update placeholders and button text on initial load
    function updateInitialText() {
        // Change the placeholder value for the search input
        const searchInput = document.querySelector('input[name="em_search"]');
        if (searchInput) {
            searchInput.placeholder = "Search";
        }

        // Change the placeholder value for the date input
        const dateInput = document.querySelector('.em-date-input.em-search-scope');
        if (dateInput) {
            dateInput.placeholder = "Date";
        }

        // Change the text of the search button
        const searchButton = document.querySelector('.em-search-submit.button-primary');
        if (searchButton) {
            searchButton.textContent = "Search";
        }

        // Update the "VER +" buttons initially
        updateReadMoreText();
    }

    // Run the initial updates if the URL matches
    if (window.location.href === "https://ani.pt/en/detailed-search-for-calls/") {
        updateInitialText();

        // Observe DOM changes for AJAX-loaded content
        const observer = new MutationObserver(function (mutationsList, observer) {
            mutationsList.forEach(function (mutation) {
                if (mutation.type === "childList") {
                    updateReadMoreText();
                }
            });
        });

        // Start observing the parent container where AJAX content is loaded
        const ajaxContainer = document.querySelector('.em-search-results'); // Replace with the correct container for your AJAX-loaded content
        if (ajaxContainer) {
            observer.observe(ajaxContainer, { childList: true, subtree: true });
        }
    }
});

jQuery(function($){
  $(window).on('load', function(){

    // Limit to toggles inside the footer area
    $('footer .et_pb_toggle_title[role="button"]').each(function(){
      const $title = $(this);

      // Skip if already fixed
      if ($title.find('button.et_pb_toggle_button').length) return;

      const label = $title.text().trim();
      const ariaControls = $title.attr('aria-controls');
      const ariaExpanded = $title.attr('aria-expanded');

      // Create accessible button
      const $button = $('', {
        class: 'et_pb_toggle_button',
        type: 'button',
        'aria-controls': ariaControls,
        'aria-expanded': ariaExpanded,
        text: label
      });

      // Remove attributes from heading and insert button
      $title.removeAttr('role tabindex aria-controls aria-expanded').empty().append($button);
    });

    // Keep aria-expanded synchronized with open/close state
    $(document).on('click', 'footer .et_pb_toggle_title button.et_pb_toggle_button', function(){
      const $toggle = $(this).closest('.et_pb_toggle');
      const isOpen = $toggle.hasClass('et_pb_toggle_open');
      $(this).attr('aria-expanded', isOpen ? 'true' : 'false');
    });

  });
});

jQuery(function($){
  $(window).on('load', function(){
    $('fieldset.hidden-fields-container').each(function(){
      const $fieldset = $(this);

      // Skip if already has a legend
      if ($fieldset.find('legend').length) return;

      // Add an accessible, hidden legend
      const $legend = $('', {
        text: 'Campos ocultos de configuração do formulário (não é necessário preencher).',
        class: 'sr-only'
      });

      $fieldset.prepend($legend);
    });
  });
});

jQuery(function($){
  $(window).on('load', function(){
    // Find Contact Form 7 CAPTCHA input fields
    $('input.wpcf7-captchar').each(function(){
      const $captcha = $(this);

      // If it already has an aria-label or aria-labelledby, skip it
      if ($captcha.attr('aria-label') || $captcha.attr('aria-labelledby')) return;

      // Add an accessible label for screen readers
      $captcha.attr({
        'aria-label': 'Campo de verificação. Introduza o texto da imagem para confirmar que é humano.'
      });
    });
  });
});

jQuery(function($){
  $(window).on('load', function(){

    $('form.et_pb_searchform').each(function(){
      const $form = $(this);
      const $input = $form.find('input.et_pb_s');

      // Remove Divi's injected labels
      $form.find('label[for="s"], label.screen-reader-text, label.daily-screen-reader-text').remove();

      // Only wrap once
      if (!$input.parent('label').length) {
        const $label = $('Pesquisar: introduza o termo que pretende procurar.').append($input.clone(true));
        $input.replaceWith($label);

        // Ensure the label behaves like a block (full width)
        $label.css('display', 'contents');
        // And make sure the input fills it
        $label.find('input').css('width', '100%');
      }
    });
  });
});

jQuery(function($){
  $(window).on('load', function(){

    // Target all submenu arrows inside your side menu
    $('.et_pb_side_nav .et_mobile_menu_arrow').each(function(){
      const $arrow = $(this);

      // Make arrow focusable
      $arrow.attr({
        'tabindex': '0',
        'role': 'button',
        'aria-expanded': $arrow.hasClass('et_pb_submenu_opened') ? 'true' : 'false'
      });

      // Let Enter or Space behave like a click
      $arrow.on('keydown', function(e){
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          e.stopPropagation();

          // Trigger Divi's own click handler
          $(this).trigger('click');

          // Update aria-expanded state after a short delay
          setTimeout(() => {
            const isOpen = $(this).hasClass('et_pb_submenu_opened');
            $(this).attr('aria-expanded', isOpen ? 'true' : 'false');
          }, 150);
        }
      });
    });

  });
});

jQuery(function($){

  // Function to make submenu arrows accessible
  function enableKeyboardForSubmenuArrows(){
    $('.menu-item-has-children .et_mobile_menu_arrow').each(function(){
      const $arrow = $(this);

      // Prevent multiple bindings
      if ($arrow.data('keyboard-ready')) return;
      $arrow.data('keyboard-ready', true);

      // Make focusable
      $arrow.attr({
        'tabindex': '0',
        'role': 'button',
        'aria-label': 'Abrir ou fechar submenu'
      });

      // Ensure it's visible to keyboard navigation
      $arrow.css({
        'cursor': 'pointer',
        'outline': 'none',
        'display': 'inline-block'
      });

      // Add Enter/Space functionality
      $arrow.on('keydown', function(e){
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          e.stopPropagation();
          $(this).trigger('click'); // simulate Divi's click

          // Update ARIA state
          setTimeout(() => {
            const $parentLink = $(this).closest('a');
            const isOpen = $(this).hasClass('et_pb_submenu_opened');
            $parentLink.attr('aria-expanded', isOpen ? 'true' : 'false');
          }, 150);
        }
      });

      console.log('✅ Accessible arrow added:', this);
    });
  }

  // Run once on load
  $(window).on('load', enableKeyboardForSubmenuArrows);

  // If the menu is dynamically loaded (mobile/side menu), observe DOM changes
  const observer = new MutationObserver(enableKeyboardForSubmenuArrows);
  observer.observe(document.body, { childList: true, subtree: true });
});

document.addEventListener("DOMContentLoaded", function () {

    let lastFocusedElement = null;
    let popupInitialized = false;

    /* ---------------------------------------------------------
       Prevent default anchor scroll for elements that trigger 
       Divi Areas popups while preserving click behavior
    --------------------------------------------------------- */
    function patchPopupAnchors() {
        document.querySelectorAll('a[href^="#"][data-trigger-click]').forEach(a => {
            a.addEventListener("click", function (e) {
                e.preventDefault();
            });
            a.addEventListener("keydown", function (e) {
                if (e.key === "Enter" || e.key === " ") {
                    e.preventDefault();
                    a.click();
                }
            });
        });
    }

    patchPopupAnchors();

    /* ---------------------------------------------------------
       Make Divi toggles keyboard accessible
    --------------------------------------------------------- */
    function makeTogglesAccessible(container) {
        const toggles = container.querySelectorAll(".et_pb_toggle .et_pb_toggle_title");
        toggles.forEach(header => {
            header.setAttribute("tabindex", "0");
            header.setAttribute("role", "button");
        });
    }

    /* ---------------------------------------------------------
       Focus first toggle or the modal container
    --------------------------------------------------------- */
    function focusFirstToggle(container) {
        const first = container.querySelector(".et_pb_toggle .et_pb_toggle_title");
        if (first) first.focus();
        else container.focus();
    }

    /* ---------------------------------------------------------
       Trap keyboard TAB navigation inside popup
    --------------------------------------------------------- */
    function setupFocusTrap(container) {
        container.addEventListener("keydown", function (e) {
            if (e.key !== "Tab") return;

            const selectors =
                'a, button, input, textarea, select, [role="button"], [tabindex]:not([tabindex="-1"])';

            const items = [...container.querySelectorAll(selectors)];
            if (items.length === 0) return;

            const first = items[0];
            const last = items[items.length - 1];

            if (e.shiftKey && document.activeElement === first) {
                e.preventDefault();
                last.focus();
            } else if (!e.shiftKey && document.activeElement === last) {
                e.preventDefault();
                first.focus();
            }
        });
    }

    /* ---------------------------------------------------------
       MutationObserver to detect popup open/close
    --------------------------------------------------------- */
    const observer = new MutationObserver(() => {

        const popup = document.querySelector(".et_pb_section.with-close.is-open");

        /* ------------------- POPUP OPEN ------------------- */
        if (popup && !popupInitialized) {
            popupInitialized = true;

            if (!lastFocusedElement)
                lastFocusedElement = document.activeElement;

            popup.setAttribute("tabindex", "-1");

            makeTogglesAccessible(popup);

            setTimeout(() => {
                focusFirstToggle(popup);
            }, 120);

            setupFocusTrap(popup);
        }

        /* ------------------- POPUP CLOSED ------------------- */
        if (!popup && popupInitialized) {

            popupInitialized = false;

            const target = lastFocusedElement;

            if (target) {
                // Ensure focusability
                target.setAttribute("tabindex", "-1");
            }

            // Attempt #1
            setTimeout(() => {
                if (target) {
                    try { target.focus({ preventScroll: true }); }
                    catch { target.focus(); }
                }
            }, 150);

            // Attempt #2 (final override)
            setTimeout(() => {
                if (target) {
                    try { target.focus({ preventScroll: true }); }
                    catch { target.focus(); }
                    target.removeAttribute("tabindex");
                }
            }, 500);

            lastFocusedElement = null;
        }

    });

    observer.observe(document.body, {
        attributes: true,
        attributeFilter: ["class"],
        subtree: true
    });

});

(function () {
  // 1) Injeta CSS (garantido)
  const css = `
    .month.input{ position: relative; }
    .month.input .em-fixed-month-title{
      position:absolute;
      top:0;
      left:0;
      font-weight:700;
      text-transform:uppercase;
      pointer-events:none;
      color:#fff;
	  font-size: 20px;
      z-index:5;
    }
    /* se quiseres esconder o texto do input sem “partir” o valor */
    .month.input input.em-month-picker{
      color:transparent !important;
      caret-color:transparent !important;
    }
  `;
  const style = document.createElement('style');
  style.setAttribute('data-em-fix-style','1');
  style.appendChild(document.createTextNode(css));
  document.head.appendChild(style);

  const MONTHS = [
    'Janeiro','Fevereiro','Março','Abril','Maio','Junho',
    'Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'
  ];

  function getCorrectLabel(picker){
    const dm = picker.getAttribute('data-month-value');
    if (dm && dm.trim()) return dm.trim();

    const v = picker.value;
    if (/^\d{4}-\d{2}$/.test(v)) {
      const y = v.slice(0,4);
      const mi = parseInt(v.slice(5,7),10) - 1;
      if (mi >= 0 && mi <= 11) return `${MONTHS[mi]} ${y}`;
    }
    return '';
  }

  function patchCalendar(cal){
    const picker = cal.querySelector('input.em-month-picker');
    const target = cal.querySelector('div.month.input');
    if (!picker || !target) return false;

    let titleEl = target.querySelector('.em-fixed-month-title');
    if (!titleEl) {
      titleEl = document.createElement('div');
      titleEl.className = 'em-fixed-month-title';
      titleEl.dataset.emOwn = "1";
      target.appendChild(titleEl);
    }

    const label = getCorrectLabel(picker);
    if (!label) return false;

    const next = label.toUpperCase();
    if (titleEl.textContent !== next) titleEl.textContent = next;
    return true;
  }

  function patchAll(){
    let ok = false;
    document.querySelectorAll('.em-calendar, table.em-calendar, .em-calendar-wrapper').forEach(cal => {
      if (patchCalendar(cal)) ok = true;
    });
    return ok;
  }

  // 2) Corre o mais cedo possível e repete até “apanhar” o calendário
  function earlyLock(){
    const start = Date.now();
    (function tick(){
      patchAll();
      if (Date.now() - start < 6000) setTimeout(tick, 150);
    })();
  }

  // 3) Observa o DOM para apanhar quando o calendário é injetado
  const obs = new MutationObserver(() => patchAll());
  obs.observe(document.documentElement, { childList:true, subtree:true });

  // 4) Arranques
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => { patchAll(); earlyLock(); });
  } else {
    patchAll(); earlyLock();
  }
  window.addEventListener('load', () => { patchAll(); });

  // 5) Após cliques nas setas/toggle
  document.addEventListener('click', function(e){
    if (e.target.closest('.em-calnav-prev, .em-calnav-next, .toggle, .em-calnav')) {
      setTimeout(patchAll, 60);
      setTimeout(patchAll, 200);
    }
  }, true);

})();

